module DIG_ROM_512X5_FilterKernel (
    input [8:0] A,
    input sel,
    output reg [4:0] D
);
    reg [4:0] my_rom [0:511];

    always @ (*) begin
        if (~sel)
            D = 5'hz;
        else
            D = my_rom[A];
    end

    initial begin
